import React, { useState } from "react";
import "./Modal.css"; // reuse modal overlay styles

const FeedbackToast = ({ onClose }) => {
  const [copied, setCopied] = useState(false);
  const email = "contactme@andrew-napier.com";

  const handleCopy = () => {
    navigator.clipboard.writeText(email).then(() => {
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    });
  };

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div
        onClick={(e) => e.stopPropagation()} // prevent overlay close when clicking inside
        style={{
          backgroundColor: "#DEDEDE",
          color: "#000",
          borderRadius: "20px",
          boxShadow: "0 4px 20px rgba(0,0,0,0.3)",
          padding: "2rem",
          width: "min(90vw, 400px)",
          height: "auto",
          display: "flex",
          flexDirection: "column",
          alignItems: "center",
          justifyContent: "space-between",
          gap: "1.5rem",
          textAlign: "center",
        }}
      >
        {/* Close button */}
        <div
          style={{
            width: "100%",
            display: "flex",
            justifyContent: "flex-end",
          }}
        >
          <button
            onClick={onClose}
            style={{
              backgroundColor: "#A0A2BD",
              color: "white",
              border: "none",
              borderRadius: "50%",
              width: "30px",
              height: "30px",
              fontSize: "16px",
              cursor: "pointer",
              transition: "background 0.2s",
            }}
            onMouseEnter={(e) => (e.target.style.backgroundColor = "#888AB0")}
            onMouseLeave={(e) => (e.target.style.backgroundColor = "#A0A2BD")}
          >
            ✕
          </button>
        </div>

        {/* Main content */}
        <div style={{ width: "100%" }}>
          <p style={{ marginBottom: "1rem" }}>
            Send feedback to:
            <br />
            <strong style={{ wordBreak: "break-all" }}>{email}</strong>
          </p>

          <button
            onClick={handleCopy}
            style={{
              backgroundColor: "#A0A2BD",
              color: "white",
              border: "none",
              borderRadius: "12px",
              padding: "0.75rem 1.5rem",
              width: "80%",
              cursor: "pointer",
              fontSize: "1rem",
              fontWeight: "500",
              transition: "background 0.2s, transform 0.1s",
            }}
            onMouseEnter={(e) => (e.target.style.backgroundColor = "#888AB0")}
            onMouseLeave={(e) => (e.target.style.backgroundColor = "#A0A2BD")}
            onMouseDown={(e) => (e.target.style.transform = "scale(0.97)")}
            onMouseUp={(e) => (e.target.style.transform = "scale(1)")}
          >
            {copied ? "Copied!" : "Copy Email"}
          </button>
        </div>
      </div>
    </div>
  );
};

export default FeedbackToast;
